    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change 1: EF Core 9 renamed the default discriminator
            // property from "Discriminator" to "$type". Existing 500K documents
            // use "Discriminator", and direct SQL queries reference c.Discriminator.
            // Preserve the old property name for data compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF Core 9 changed the default id format from
            // "EntityType|KeyValue" (e.g. "Product|123") to just the raw key
            // value (e.g. "123"). Existing documents use the old format, so we
            // must opt back in to keep them readable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.Internal.IdValueGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change 3: EF Core 9 Cosmos provider removed synchronous
        // I/O (ToList, First, etc.) by default. If sync calls are still needed
        // during migration, opt back in. Prefer converting to async long-term.
        // optionsBuilder.UseCosmos(... , o => o.AllowSynchronousIO());

        base.OnConfiguring(optionsBuilder);
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

