class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we preserved "Discriminator" in OnModelCreating.
        // If we had NOT configured HasDiscriminator("Discriminator"), EF Core 9 would
        // write "$type" instead, and this query would silently return zero results.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Breaking change 3 fix: sync APIs (ToList, First, Single, etc.) now throw
        // InvalidOperationException unless AllowSynchronousIO() is enabled.
        // Convert to async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

