using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change 1 — Discriminator property renamed
            // EF Core 9 renamed the default discriminator property from
            // "Discriminator" to "$type". Existing 500K documents use
            // "Discriminator", and direct SQL queries reference c.Discriminator.
            // Preserve the old property name for data compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2 — id value format changed
            // EF Core 8 generated compound ids: "Product|123".
            // EF Core 9 uses just the key value: "123".
            // Existing documents cannot be found without this converter.
            entity.Property(p => p.Id)
                .ToJsonProperty("id")
                .HasConversion(
                    v => $"Product|{v}",
                    v => int.Parse(v.Replace("Product|", "")));

            // Breaking change 4 — HasIndex throws for Cosmos
            // EF Core 9 now throws InvalidOperationException for HasIndex on
            // Cosmos entities since Cosmos manages indexing at the container
            // level, not per-property. The HasIndex(p => p.Sku) call was removed.
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change 3 — Synchronous I/O removed
        // EF Core 9 Cosmos provider throws InvalidOperationException for sync
        // APIs (ToList, First, SaveChanges, etc.) by default.
        // Prefer converting all call sites to async. If that's not feasible
        // immediately, opt back in during the transition:
        // optionsBuilder.UseCosmos(... , o => o.AllowSynchronousIO());

        base.OnConfiguring(optionsBuilder);
    }
}

